const items = $input.all();
const now = new Date();
const currentMonth = now.getMonth(); // 0-indexed
const currentYear = now.getFullYear();

// === DEBUG: muestreo de datos crudos ===
const sample = items.slice(0, 5).map(i => i.json['FECHA_CARGUE_VIAJE']);
console.log('[Filtrar Mes Actual] Total filas recibidas:', items.length);
console.log('[Filtrar Mes Actual] Muestra FECHA_CARGUE_VIAJE (primeras 5):', JSON.stringify(sample));
console.log('[Filtrar Mes Actual] Filtrando para mes:', currentMonth + 1, '/', currentYear);

function parseFecha(raw) {
  if (raw === null || raw === undefined || raw === '') return null;
  const s = String(raw).trim();
  if (s === '') return null;

  // Paso 1: separar parte de fecha de la hora (si viene '11/08/2025 10:00:00')
  const datePart = s.split(' ')[0];

  // Serial date de Google Sheets (número como 45752)
  if (/^\d{4,5}(\.\d+)?$/.test(datePart)) {
    const serial = parseFloat(datePart);
    if (serial > 1 && serial < 200000) {
      const epoch = new Date(1899, 11, 30);
      epoch.setDate(epoch.getDate() + Math.floor(serial));
      return epoch;
    }
    return null;
  }

  let m;

  // DD/MM/YYYY o DD-MM-YYYY (formato Colombia)
  m = datePart.match(/^(\d{1,2})[\/-](\d{1,2})[\/-](\d{4})$/);
  if (m) {
    const day = parseInt(m[1], 10);
    const mon = parseInt(m[2], 10);
    const year = parseInt(m[3], 10);
    if (mon >= 1 && mon <= 12 && day >= 1 && day <= 31) {
      return new Date(year, mon - 1, day);
    }
    return null;
  }

  // YYYY-MM-DD o YYYY/MM/DD (ISO)
  m = datePart.match(/^(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})$/);
  if (m) {
    const year = parseInt(m[1], 10);
    const mon = parseInt(m[2], 10);
    const day = parseInt(m[3], 10);
    if (mon >= 1 && mon <= 12 && day >= 1 && day <= 31) {
      return new Date(year, mon - 1, day);
    }
    return null;
  }

  // NO hay fallback — si no matchea, se descarta
  return null;
}

let validCount = 0;
let skippedEmpty = 0;
let skippedUnparseable = 0;
const filtered = [];

for (const item of items) {
  const raw = item.json['FECHA_CARGUE_VIAJE'];
  if (!raw || String(raw).trim() === '') { skippedEmpty++; continue; }

  const fecha = parseFecha(raw);
  if (!fecha || isNaN(fecha.getTime())) { skippedUnparseable++; continue; }
  validCount++;

  if (fecha.getMonth() === currentMonth && fecha.getFullYear() === currentYear) {
    filtered.push(item);
  }
}

console.log('[Filtrar Mes Actual] Filas vacias (sin fecha):', skippedEmpty);
console.log('[Filtrar Mes Actual] Filas con fecha no parseable:', skippedUnparseable);
console.log('[Filtrar Mes Actual] Filas con fecha valida:', validCount);
console.log('[Filtrar Mes Actual] >>> Filas que pasan filtro (mes actual):', filtered.length);

return filtered.length > 0 ? filtered : [{ json: { _empty: true } }];

const items = $input.all();

// Si vino vacío del filtro, retornar estructura vacía
if (items.length === 1 && items[0].json._empty) {
  return [{
    json: {
      totalPedidos: 0,
      pedidosSinEstado: 0,
      pedidosPendientes: 0,
      pedidosConNovedad: 0,
      pedidosRechazados: 0,
      pedidosEntregadosOK: 0,
      listaPedidos: []
    }
  }];
}

const pedidos = items.map(item => {
  const d = item.json;
  return {
    consecutivo: d['CONSECUTIVO IMP / LOG / CRM'] || '',
    empresa: d['EMPRESA'] || '',
    fechaCargue: d['FECHA_CARGUE_VIAJE'] || '',
    fechaEstimada: d['FECHA ESTIMADA CARGUE'] || '',
    fechaEntrega: d['FECHA REQUERIDA DE ENTREGA'] || '',
    origen: d['ORIGEN'] || '',
    destino: d['DESTINO'] || '',
    proveedor: d['Proveedor'] || '',
    estado: d['ESTADO'] || '',
    novedad: d['NOVEDAD'] || '',
    comentarioNovedad1: d['Comentario Novedad'] || '',
    comentarioNovedad2: d['Comentario Novedad2'] || '',
    comentarioNovedad3: d['Comentario Novedad3'] || '',
    entregaCliente1: d['ENTREGA A CLIENTE'] || '',
    entregaCliente2: d['ENTREGA A CLIENTE2'] || '',
    entregaCliente3: d['ENTREGA A CLIENTE3'] || '',
    valorMercancia: d['VALOR DE LA MERCANCIA'] || '',
    rtTotal: d['ID_VIAJE_LINK'] || '',
    coordinador: d['COORDINADOR DEL SERVICIO'] || '',
    vendedor: d['VENDEDOR QUE SOLICITA'] || '',
    cliente: d['CLIENTE'] || '',
    llegadaCargue: d['LLEGADA A CARGUE'] || '',
    salidaCargue: d['SALIDA DE CARGUE'] || '',
    llegadaDescargue: d['LLEGADA A DESCARGUE'] || '',
    salidaDescargue: d['SALIDA DE DESCARGUE'] || '',
    fotoCumplido: d['FOTO CUMPLIDO'] || ''
  };
});

return [{
  json: {
    totalPedidos: pedidos.length,
    pedidosSinEstado: pedidos.filter(p => !p.estado || p.estado.trim() === '').length,
    pedidosPendientes: pedidos.filter(p => p.estado === 'Pendiente').length,
    pedidosConNovedad: pedidos.filter(p => p.estado === 'Entregado con Novedad').length,
    pedidosRechazados: pedidos.filter(p => p.estado === 'Rechazado por Cliente').length,
    pedidosEntregadosOK: pedidos.filter(p => p.estado === 'Entregado OK').length,
    listaPedidos: pedidos
  }
}];
